const incoming = $('Webhook').first().json;
const headers = incoming.headers || {};
const body = incoming.body || {};

const incomingToken = (headers['x-admin-token'] || '').trim();
const storedToken = ($('Load Admin Token').first().json.value || '').trim();
const action = (body.action || '').trim();

if (!incomingToken || incomingToken !== storedToken) {
  return [{ json: { authorized: false, statusCode: 401, error: 'unauthorized', action: '' } }];
}

const allowed = ['health', 'bookings', 'templates'];
if (!allowed.includes(action)) {
  return [{ json: { authorized: true, statusCode: 400, error: 'unknown_action', action } }];
}

return [{ json: { authorized: true, statusCode: 200, error: '', action } }];

const r = $input.first().json;

// Market stats from competitor_sources + observations
const mMin = r.cs_market_min ? parseFloat(r.cs_market_min) : (r.market_min ? parseFloat(r.market_min) : null);
const mMed = r.cs_market_median ? parseFloat(r.cs_market_median) : (r.market_median ? parseFloat(r.market_median) : null);
const mAvg = r.cs_market_avg ? parseFloat(r.cs_market_avg) : (r.market_avg ? parseFloat(r.market_avg) : null);
const mMax = r.cs_market_max ? parseFloat(r.cs_market_max) : (r.market_max ? parseFloat(r.market_max) : null);

return [{ json: {
  ok: true,
  action: 'revenue',
  summary: {
    total_gaps: parseInt(r.total_gaps) || 0,
    total_estimated_loss: parseFloat(r.total_estimated_loss) || 0,
    one_night_gaps: parseInt(r.one_night_gaps) || 0,
    two_night_gaps: parseInt(r.two_night_gaps) || 0,
    three_night_gaps: parseInt(r.three_night_gaps) || 0,
    competitor_count: parseInt(r.competitor_count) || 0,
    competitor_sources_count: parseInt(r.competitor_sources_count) || 0,
    active_competitors_count: parseInt(r.active_competitors_count) || 0,
    excluded_competitors_count: parseInt(r.excluded_competitors_count) || 0,
    market_min: mMin,
    market_median: mMed,
    market_avg: mAvg,
    market_max: mMax,
    latest_market_median_from_sources: mMed,
    latest_market_avg_from_sources: mAvg,
    latest_market_min_from_sources: mMin,
    latest_market_max_from_sources: mMax,
    recommendations_count: parseInt(r.recommendations_count) || 0
  },
  gap_windows: r.gap_windows ? (typeof r.gap_windows === 'string' ? JSON.parse(r.gap_windows) : r.gap_windows) : [],
  competitor_prices: r.competitor_prices ? (typeof r.competitor_prices === 'string' ? JSON.parse(r.competitor_prices) : r.competitor_prices) : [],
  latest_observations: r.latest_observations ? (typeof r.latest_observations === 'string' ? JSON.parse(r.latest_observations) : r.latest_observations) : []
}}];

const rows = $input.all().map(i => i.json);
return [{ json: {
  ok: true,
  action: 'competitor_sources',
  competitor_sources: rows,
  summary: {
    total: rows.length,
    active: rows.filter(r=>r.status==='active').length,
    excluded: rows.filter(r=>r.status==='excluded').length
  }
}}];

const rows = $input.all().map(i => i.json);
return [{ json: {
  ok: true,
  action: 'competitor_price_observations',
  observations: rows,
  count: rows.length
}}];

const r = $input.first().json;
const staleWarning = (r.fresh_observations_14d === 0)
  ? 'Все данные seed/устаревшие (> 14 дней). Рекомендуется ручная проверка цен конкурентов.'
  : null;
return [{ json: {
  ok: true,
  action: 'competitor_market_summary',
  market: {
    active_sources: r.active_sources,
    excluded_sources: r.excluded_sources,
    market_min: r.market_min ? parseFloat(r.market_min) : null,
    market_median: r.market_median ? parseFloat(r.market_median) : null,
    market_avg: r.market_avg ? parseFloat(r.market_avg) : null,
    market_max: r.market_max ? parseFloat(r.market_max) : null,
    total_observations: r.total_observations,
    fresh_observations_14d: r.fresh_observations_14d,
    latest_observed_at: r.latest_observed_at,
    stale_warning: staleWarning,
    competitor_details: r.competitor_details
  }
}}];

const body = ($('Webhook').first().json.body) || $input.first().json || {};
const id = body.competitor_source_id || body.id || null;
const price_per_night = body.price_per_night ? parseFloat(body.price_per_night) : null;
const stay_date_from = body.stay_date_from || body.date_from || null;
const stay_date_to = body.stay_date_to || body.date_to || null;
const notes = body.notes || 'manual_input via Admin API';
const confidence = body.confidence ? parseFloat(body.confidence) : 0.90;

if (!id || !price_per_night || !stay_date_from || !stay_date_to) {
  throw new Error('Missing required fields: competitor_source_id, price_per_night, stay_date_from, stay_date_to');
}

const nights = Math.round((new Date(stay_date_to) - new Date(stay_date_from)) / 86400000);

return [{json: {
  q_id: id,
  q_price: price_per_night,
  q_from: stay_date_from,
  q_to: stay_date_to,
  q_nights: nights,
  q_confidence: confidence,
  q_notes: notes
}}];
